const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;

  // Validate mandatory fields
  const requiredFields = ['request_id', 'source', 'finance_request_type'];
  const missingFields = requiredFields.filter(field => !data[field]);

  if (missingFields.length > 0) {
    throw new Error(`Missing mandatory fields: ${missingFields.join(', ')}`);
  }

  // Validate source
  if (!['CEO', 'CBS'].includes(data.source)) {
    throw new Error(`Invalid source: ${data.source}. Must be CEO or CBS`);
  }

  // Validate finance_request_type
  const validTypes = ['budget', 'forecast', 'invoice', 'pricing'];
  if (!validTypes.includes(data.finance_request_type)) {
    throw new Error(`Invalid finance_request_type: ${data.finance_request_type}`);
  }

  const systemCurrency = $('Workflow Configuration').first().json.system_currency;
  const inputCurrency = data.currency || systemCurrency;

  // Currency validation - reject if mismatch
  if (inputCurrency !== systemCurrency) {
    throw new Error(`Currency mismatch: Request currency '${inputCurrency}' does not match system currency '${systemCurrency}'. Currency conversion not supported.`);
  }

  const amount = parseFloat(data.amount) || 0;
  const threshold = $('Workflow Configuration').first().json.approval_threshold;

  // Normalize and structure output
  const normalized = {
    finance_id: `FIN-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    request_id: data.request_id,
    source: data.source,
    type: data.finance_request_type,
    intent_summary: data.intent_summary || '',
    amount: amount,
    original_amount: amount,
    currency: inputCurrency,
    mode: data.mode || 'simulation',
    timestamp: new Date().toISOString(),
    approval_required: amount > threshold,
    raw_input: data
  };

  output.push({ json: normalized });
}

return output;

