const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;

  // Apply cost audit adjusted_amount if available and greater than 0
  const costAudit = data.cost_audit || {};
  const adjustedAmount = parseFloat(costAudit.adjusted_amount) || 0;
  const originalAmount = data.amount;

  let finalAmount = originalAmount;
  let amountAdjusted = false;
  let adjustmentReason = '';

  if (adjustedAmount > 0 && adjustedAmount !== originalAmount) {
    finalAmount = adjustedAmount;
    amountAdjusted = true;
    adjustmentReason = `Cost audit adjusted amount from ${originalAmount} to ${adjustedAmount}`;
  }

  // Update approval_required flag based on final amount
  const threshold = $('Workflow Configuration').first().json.approval_threshold;
  const riskLevel = data.risk_analysis?.risk_level || 'unknown';
  const riskScore = data.risk_analysis?.risk_score || 0;
  const riskScoreThreshold = $('Workflow Configuration').first().json.risk_score_threshold;

  const approvalRequired = finalAmount > threshold || riskLevel !== 'low' || riskScore >= riskScoreThreshold;

  output.push({
    json: {
      ...data,
      amount: finalAmount,
      amount_adjusted: amountAdjusted,
      adjustment_reason: adjustmentReason,
      approval_required: approvalRequired
    }
  });
}

return output;

