const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;

  // CRITICAL: Get confidence from WF-0 trigger ONLY
  const triggerData = $('Execute Workflow Trigger').item.json;
  const confidence = triggerData.confidence || 0;

  // Get risk_level from WF-0 trigger
  const riskLevel = triggerData.risk_level || 'unknown';

  // Map status to standardized values
  let status = 'unknown';
  const rawStatus = data.execution_status || data.status;

  if (rawStatus === 'completed') {
    status = 'completed';
  } else if (rawStatus === 'simulation_only' || rawStatus === 'simulation_block') {
    status = 'simulation_only';
  } else if (rawStatus === 'paused' || rawStatus === 'revision_requested') {
    status = 'paused';
  } else if (rawStatus === 'blocked' || rawStatus === 'escalated_simulation' || rawStatus === 'fraud_alert_escalated') {
    status = 'blocked';
  } else if (rawStatus === 'rejected') {
    status = 'rejected';
  } else if (data.approved === true) {
    status = 'completed';
  } else if (data.approved === false) {
    status = 'rejected';
  }

  // Build decision summary
  let decisionSummary = '';
  if (data.executive_summary) {
    decisionSummary = data.executive_summary;
  } else if (data.approval_reason) {
    decisionSummary = data.approval_reason;
  } else if (data.rejection_reason) {
    decisionSummary = data.rejection_reason;
  } else if (data.escalation_reason) {
    decisionSummary = data.escalation_reason;
  } else if (data.decision_summary) {
    decisionSummary = data.decision_summary;
  } else {
    decisionSummary = `Finance request processed with status: ${status}`;
  }

  // Calculate financial_impact as string based on amount thresholds
  const amount = data.amount || 0;
  let financialImpact = 'low';
  if (amount > 500000) {
    financialImpact = 'high';
  } else if (amount > 100000) {
    financialImpact = 'medium';
  }

  // Determine founder approval requirement
  const founderApprovalRequired = data.requires_ceo_review || data.escalated_to_ceo || data.founder_approval_required || false;

  // Build approvals array
  const approvals = [];
  if (data.approval_type) {
    approvals.push({
      approver: data.approval_type,
      decision: data.approved ? 'approved' : 'rejected',
      timestamp: data.approval_timestamp || data.timestamp || new Date().toISOString(),
      comments: data.comments || data.approval_reason || ''
    });
  }
  if (data.founder_approved || data.founder_approval_granted) {
    approvals.push({
      approver: 'founder',
      decision: 'approved',
      timestamp: data.founder_approval_timestamp || data.approval_timestamp || new Date().toISOString(),
      comments: data.founder_comments || 'Founder approval granted'
    });
  }

  // Determine next allowed actions
  const nextAllowedActions = [];
  if (status === 'completed' && data.mode === 'execute') {
    nextAllowedActions.push('execute_payment', 'monitor_execution');
  } else if (status === 'completed' && data.mode === 'simulation') {
    nextAllowedActions.push('convert_to_execution', 'review_simulation');
  } else if (status === 'paused') {
    nextAllowedActions.push('resubmit_request', 'cancel_request');
  } else if (status === 'rejected') {
    nextAllowedActions.push('appeal_decision', 'cancel_request');
  } else if (status === 'blocked' || founderApprovalRequired) {
    nextAllowedActions.push('await_founder_approval');
  }

  // Build audit object
  const audit = {
    timestamp: new Date().toISOString(),
    performed_by: 'WF-2',
    notes: [
      `Finance request ${data.finance_id || data.request_id} processed`,
      `Status: ${status}`,
      `Risk Level: ${riskLevel}`,
      `Confidence: ${confidence}`
    ].join(' | ')
  };

  // Construct ONLY standardized output - DROP all other fields
  const normalized = {
    workflow_id: 'WF-2',
    request_id: data.request_id || data.finance_id || 'unknown',
    status: status,
    decision_summary: decisionSummary,
    confidence: confidence,
    risk_level: riskLevel,
    financial_impact: financialImpact,
    amount: amount,
    founder_approval_required: founderApprovalRequired,
    approvals: approvals,
    next_allowed_actions: nextAllowedActions,
    audit: audit
  };

  output.push({ json: normalized });
}

return output;

const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;

  // Determine execution or non-execution reason
  let executionReason = '';
  if (data.execution_status === 'completed') {
    executionReason = 'Approved and executed successfully';
  } else if (data.execution_status === 'simulation_only') {
    executionReason = 'Simulation mode - no execution performed';
  } else if (data.execution_status === 'rejected') {
    executionReason = data.rejection_reason || 'Request rejected';
  } else if (data.execution_status === 'escalated_simulation') {
    executionReason = data.escalation_reason || 'Escalated to CEO';
  } else if (data.execution_status === 'fraud_alert_escalated') {
    executionReason = data.escalation_reason || 'Fraud alert detected';
  } else if (data.execution_status === 'revision_requested') {
    executionReason = data.revision_comments || 'Revision requested';
  } else {
    executionReason = 'Unknown status';
  }

  // Collect all approvals
  const allApprovals = [];
  if (data.approved && data.approval_type === 'auto') {
    allApprovals.push({
      type: 'auto',
      timestamp: data.approval_timestamp,
      reason: data.approval_reason
    });
  }
  if (data.approved && data.approval_type === 'cfo') {
    allApprovals.push({
      type: 'cfo',
      timestamp: data.approval_timestamp,
      decision: 'Approve'
    });
  }
  if (data.founder_approved) {
    allApprovals.push({
      type: 'founder',
      timestamp: data.approval_timestamp || new Date().toISOString()
    });
  }

  // Calculate financial impact
  const financialImpact = {
    original_amount: data.original_amount || data.amount,
    final_amount: data.amount,
    adjusted: data.amount_adjusted || false,
    adjustment_reason: data.adjustment_reason || '',
    savings_potential: data.cost_audit?.savings_potential || 0,
    currency: data.currency
  };

  // Get system confidence from WF-0 trigger (never override)
  const systemConfidence = $('Execute Workflow Trigger').item.json.confidence;

  // Optional: capture finance-specific confidence separately if needed
  const financeConfidence = data.cost_audit?.audit_confidence || null;

  // Create immutable audit entry
  const auditEntry = {
    workflow_id: 'WF-2',
    request_id: data.request_id,
    finance_id: data.finance_id,
    mode: data.mode,
    amount: data.amount,
    approval_state: data.approved ? 'approved' : 'not_approved',
    execution_or_non_execution_reason: executionReason,
    timestamp: new Date().toISOString(),
    all_approvals: allApprovals,
    risk_level: data.risk_analysis?.risk_level || 'unknown',
    risk_score: data.risk_analysis?.risk_score || 0,
    confidence: systemConfidence,
    finance_confidence: financeConfidence,
    financial_impact: financialImpact,
    execution_status: data.execution_status,
    source: data.source,
    type: data.type,
    fraud_check: data.risk_ops?.fraud_check || null,
    trading_ops_executed: !!data.trading_ops,
    risk_ops_executed: !!data.risk_ops
  };

  // Return item with audit_entry field
  output.push({
    json: {
      ...data,
      audit_entry: auditEntry
    }
  });
}

return output;
